/**
 * EventDelegator runtime version.
 *
 * Build-time bundles inject __EVENT_DELEGATOR_VERSION__ via esbuild --define.
 * Source/dev mode falls back to "dev".
 */
const VERSION =
    typeof __EVENT_DELEGATOR_VERSION__ !== "undefined" && __EVENT_DELEGATOR_VERSION__
        ? __EVENT_DELEGATOR_VERSION__
        : "dev";

export default VERSION;
