/**
 * EventDelegator
 * ----------------
 * A root-scoped, service-style event delegation primitive.
 *
 * Core characteristics:
 * - Single attachment point (root)
 * - Cached native listeners per (eventType + options)
 * - Internal routing table for selectors and handlers
 * - Service lifecycle control (start / stop / pause / resume)
 * - Optional host for environment tooling (no globals)
 * - Pluggable error handling policy
 * - Taggable handlers for SPA / stateful teardown
 *
 * Design goals:
 * - Minimal surface area
 * - No implicit globals or auto-negotiation
 * - BYOB (bring your own root / environment)
 * - Predictable teardown and rebinding
 * - Introspection-friendly (for monitoring / custom consoles)
 *
 * This module does NOT:
 * - Bind per-element listeners
 * - Query the DOM at registration time
 * - Manage application state
 *
 * Delegation model:
 * - One native listener per (eventType + optionsKey)
 * - All handler dispatch resolved at event time
 *
 * Intended usage:
 * - Browser DOM event delegation
 * - SPA page/module lifecycle management
 * - Embedded or sandboxed DOM environments
 *
 * @license MTL-10
 */

class EventDelegator {

    // -----------------------------
    // Constructor / configuration
    // -----------------------------

    /**
     * Create a new EventDelegator instance.
     *
     * @constructor
     *
     * @param {Object} [config]
     * @param {EventTarget} [config.root]
     *        Optional root event target to which native listeners are attached.
     *        Must implement `addEventListener` and `removeEventListener`.
     *        Examples: `document`, `Element`, `ShadowRoot`, or any EventTarget.
     *
     *        If omitted, the delegator is constructed in an inert state.
     *        Call `setRoot(root)` to configure the root before starting the service.
     *        Calling `start()` without a configured root will throw.
     *
     * @param {Object|Function|null} [config.host]
     *        Optional environment / tooling surface.
     *        This object is not required for delegation to function.
     *        It may provide:
     *        - `validateSelector(selector)` — optional selector validation
     *        - `matches(el, selector)`      — custom selector matching
     *        - `closest(el, selector)`      — custom ancestor matching
     *        - `getPath(event)`             — custom event path resolution
     *        - `onError(error, context)`    — host-level error hook
     *
     * @param {Function|null} [config.callbackError]
     *        Optional handler error policy.
     *        - If a function is provided, it will be called when a delegated
     *          handler throws.
     *        - If `null`, handler errors are swallowed.
     *        - If omitted, a default policy is used (`console.error`).
     *
     * @param {...any} [config.*]
     *        Reserved for future configuration options.
     *        Unknown options are stored but otherwise ignored.
     *
     * @example
     * const delegator = new EventDelegator({
     *   root: document,
     *   callbackError: (msg, err) => console.error(msg, err)
     * });
     *
     * delegator.start();
     */
    constructor({ root, host, callbackError, ...opts } = {}) {
	this._opts = opts;
	//forward declarations for readability.
        this.callbackError = null;
	this.root = null;
	this.host = null;
	this._rootAdd = null;
	this._rootRemove = null;
	this._running = false;
	/**
	 * eventType -> { optionsKey -> ListenerRecord }
	 * ListenerRecord = { options, routes: Map<selector, Set<handler>>, listenerFn }
	 *
	 * We key by optionsKey because add/removeEventListener requires the same capture flag.
	 * (and we support capture/passive/once).
	 */
	this._events = new Map();

	// just a kill switch.
	this._disposed = false;

	// error callback (policy lives here, not in dispatcher)
	this.setCallbackError(callbackError);


	// ALL setup related to root/host goes through setRoot (BYOB)
	// Root is optional: delegator can be constructed inert and armed later via setRoot().
	if (root != null) {
	    this.setRoot(root, host);
	} else if (host !== undefined) {
	    this.setHost(host);
	}
    }

    /**
     * Set (or replace) the delegation root.
     *
     * This updates the single attachment point used for all native listeners.
     * If the delegator is currently running, listeners are detached from the
     * old root and re-attached to the new root (routes/handlers are preserved).
     *
     * @param {EventTarget} root
     *        The new root EventTarget to attach native listeners to.
     *        Must implement `addEventListener` and `removeEventListener`.
     *
     * @param {Object|Function|null} [host]
     *        Optional environment/tooling surface. If provided (including `null`),
     *        `setHost(host)` will be called as a convenience.
     *        If omitted (`undefined`), the existing host is left unchanged.
     *
     * @returns {this}
     *
     * @throws {Error}
     *        If called after `dispose()`.
     * @throws {Error}
     *        If `root` is missing or does not implement the required EventTarget interface.
     *
     * @example
     * // Swap root while preserving routes.
     * delegator.start();
     * delegator.setRoot(document.body);
     *
     * @example
     * // Swap root and host together.
     * delegator.setRoot(shadowRoot, window);
     */
    setRoot(root, host) {
	if (this._disposed) throw new Error("[delegator] cannot setRoot() after dispose()");

	// Validate new root first (so we don't teardown if it's invalid)
	if (!root) throw new Error("[delegator] requires a root EventTarget");

	const add = root.addEventListener;
	const remove = root.removeEventListener;

	if (typeof add !== "function" || typeof remove !== "function") {
            throw new Error("[delegator] root must implement addEventListener/removeEventListener");
	}

	const wasRunning = this._running;

	// If running, detach from OLD root (without changing running state)
	if (wasRunning) this._teardownListeners(undefined,true);

	// Capture new delegates
	this._rootAdd = (type, fn, options) => add.call(root, type, fn, options);
	this._rootRemove = (type, fn, options) => remove.call(root, type, fn, options);

	this.root = root;

	// Convenience: set host if provided
	if (host !== undefined) this.setHost(host);

	// If running, reattach to NEW root (without changing running state)
	if (wasRunning) this._setupListeners();

	return this;
    }
    /**
     * Set or replace the host environment surface.
     *
     * The host provides optional, injected capabilities used by the delegator,
     * such as selector validation, environment helpers, or error hooks.
     * It is not required for event delegation to function.
     *
     * This method does not attach or detach any listeners and does not affect
     * the current running/paused state.
     *
     * @param {Object|Function|null|undefined} [host]
     *        Optional environment/tooling surface.
     *        - If an object or function is provided, it is validated and stored.
     *        - If `null` or `undefined`, the current host is cleared.
     *
     *        Supported optional properties (validated only if present):
     *        - `matches(el, selector)`        — custom selector matching
     *        - `closest(el, selector)`        — custom ancestor matching
     *        - `getPath(event)`               — custom event path resolution
     *        - `validateSelector(selector)`   — selector validation hook
     *        - `onError(error, context)`      — error handling hook
     *
     * @returns {this}
     *
     * @throws {Error}
     *        If called after `dispose()`.
     * @throws {Error}
     *        If `host` is provided but is not an object/function, or if any
     *        provided capability is not a function.
     *
     * @example
     * delegator.setHost({
     *   validateSelector: sel => document.querySelector(sel),
     *   onError: (err, ctx) => console.error(err, ctx)
     * });
     *
     * @example
     * // Clear the host
     * delegator.setHost(null);
     */
    setHost(host) {
	if (this._disposed) throw new Error("[delegator] cannot setHost() after dispose()");

	// host is optional; null clears it
	if (host == null) {
	    this.host = null;
	    return this;
	}

	// host must be an object/function (window/globalThis are objects; some envs may pass a callable)
	const t = typeof host;
	if ((t !== "object" && t !== "function") || Array.isArray(host)) {
	    throw new Error("[delegator] host must be an object/function when provided");
	}

	// Optional capabilities (validate only if present)
	if (host.matches != null && typeof host.matches !== "function") {
	    throw new Error("[delegator] host.matches must be a function when provided");
	}
	if (host.closest != null && typeof host.closest !== "function") {
	    throw new Error("[delegator] host.closest must be a function when provided");
	}
	if (host.getPath != null && typeof host.getPath !== "function") {
	    throw new Error("[delegator] host.getPath must be a function when provided");
	}
	if (host.validateSelector != null && typeof host.validateSelector !== "function") {
	    throw new Error("[delegator] host.validateSelector must be a function when provided");
	}
	if (host.onError != null && typeof host.onError !== "function") {
	    throw new Error("[delegator] host.onError must be a function when provided");
	}
	// FIXUP(hr): host hooks are now invoked by dispatch/error paths, but the
	// pluggable contract is intentionally minimal and may be expanded later.

	this.host = host;
	return this;
    }


    /**
     * Set the handler error policy.
     *
     * This callback is invoked whenever a delegated handler throws during
     * dispatch. It centralizes error handling and prevents errors from
     * leaking out of the delegation layer.
     *
     * This method does not affect listener attachment or service state.
     *
     * @param {Function|null} [fn]
     *        Error handling policy.
     *        - If a function is provided, it will be called with:
     *          `(message, error, context)`
     *        - If `null`, handler errors are swallowed silently.
     *        - If omitted (`undefined`), the default policy is restored
     *          (`console.error`).
     *
     * @returns {this}
     *
     * @throws {Error}
     *        If called after `dispose()`.
     * @throws {Error}
     *        If `fn` is provided but is not a function or `null`.
     *
     * @example
     * // Custom error handling
     * delegator.setCallbackError((msg, err, ctx) => {
     *   logToService(msg, err, ctx);
     * });
     *
     * @example
     * // Disable error reporting
     * delegator.setCallbackError(null);
     *
     * @example
     * // Restore default behavior
     * delegator.setCallbackError();
     */
    setCallbackError(fn) {
	if (this._disposed) throw new Error("[delegator] cannot setCallbackError() after dispose()");

	// default policy: error
	if (fn === undefined) {
	    this.callbackError = (msg, err) => console.error(msg, err);
	    return this;
	}

	// allow null to mean "swallow"
	if (fn === null) {
	    this.callbackError = null;
	    return this;
	}

	if (typeof fn !== "function") {
	    throw new Error("[delegator] callbackError must be a function, null, or undefined");
	}

	this.callbackError = fn;
	return this;
    }


    // -----------------------------
    // Service lifecycle
    // -----------------------------

    /**
     * Start the delegator service.
     *
     * Attaches all currently registered native listeners to the configured root.
     * This enables event dispatch for all previously registered routes.
     *
     * Calling `start()` when the delegator is already running is a no-op.
     *
     * This method does not register or modify any handlers; it only affects
     * physical listener attachment.
     *
     * @returns {void}
     *
     * @throws {Error}
     *        If called after `dispose()`.
     * @throws {Error}
     *        If root is not configured, or if root listener methods are unavailable.
     *
     * @example
     * delegator.on({ eventType: "click", selector: ".btn", handler });
     * delegator.start(); // native listeners are attached
     */
    start() {
	this._assertNotDisposed();
	this._assertRoot();
	if (this._running) return;

	for (const [type, bucket] of this._events.entries()) {
            for (const rec of bucket.values()) {
		this._addListener(type, rec.listenerFn, rec.options);
            }
	}

	this._running = true;
    }

    /**
     * Stop the delegator service.
     *
     * Detaches all native listeners from the current root while preserving
     * all registered routes and handlers.
     *
     * Calling `stop()` when the delegator is already stopped is a no-op.
     *
     * This method does not unregister handlers or clear internal state;
     * it only disables physical event dispatch.
     *
     * @returns {void}
     *
     * @throws {Error}
     *        If called after `dispose()`.
     * @throws {Error}
     *        If running and root listener methods are unavailable.
     *
     * @example
     * delegator.start();
     * delegator.stop(); // native listeners are detached
     *
     * // Routes remain intact
     * delegator.start(); // listeners are re-attached
     */

    stop() {
	this._assertNotDisposed();
	if (!this._running) return;
	this._assertRoot();
	this._teardownListeners();
	this._running = false;
    }
    
    /**
     * Pause the delegator service.
     *
     * This is an alias for {@link stop}. It detaches all native listeners
     * from the current root while preserving all registered routes and handlers.
     *
     * Provided for semantic clarity when treating the delegator as a
     * long-running service.
     *
     * @returns {void}
     *
     * @throws {Error}
     *        If called after `dispose()`.
     * @throws {Error}
     *        If running and root listener methods are unavailable (via `stop()`).
     *
     * @example
     * delegator.pause(); // equivalent to delegator.stop()
     */
    pause() {
	this.stop();
    }
    /**
     * Resume the delegator service.
     *
     * This is an alias for {@link start}. It re-attaches all native listeners
     * to the current root and enables event dispatch for all registered routes.
     *
     * Provided for semantic clarity when treating the delegator as a
     * long-running service.
     *
     * @returns {void}
     *
     * @throws {Error}
     *        If called after `dispose()`.
     * @throws {Error}
     *        If root is not configured, or if root listener methods are unavailable.
     *
     * @example
     * delegator.resume(); // equivalent to delegator.start()
     */
    resume() {
	this.start();
    }
    /**
     * Check whether the delegator service is currently running.
     *
     * When running, native listeners are attached to the current root and
     * delegated handlers may be dispatched.
     *
     * @returns {boolean}
     *          `true` if the delegator is running; `false` if paused or stopped.
     *
     * @example
     * if (!delegator.isRunning()) {
     *   delegator.start();
     * }
     */
    isRunning() {
	return !!this._running;
    }

    /**
     * Get the current service state.
     *
     * This provides a human-readable representation of the delegator’s
     * lifecycle status.
     *
     * Possible values:
     * - `"running"` — native listeners are attached and events may dispatch
     * - `"paused"`  — native listeners are detached, routes are preserved
     *
     * @returns {"running"|"paused"}
     *
     * @example
     * if (delegator.state() === "paused") {
     *   delegator.resume();
     * }
     */
    
    state() {
	return this._running ? "running" : "paused";
    }

    // -----------------------------
    // Public API – registration
    // -----------------------------
    /**
     * Register a delegated handler (adds alongside existing handlers).
     *
     * Registration updates the internal routing table. A native listener for the
     * given `(eventType + options)` is created/attached as needed (and only when
     * the service is running).
     *
     * Handlers may be annotated with an optional `tag` for later teardown (e.g.
     * SPA page/module unload).
     *
     * @param {Object} params
     * @param {string} params.eventType
     *        DOM event type (e.g. `"click"`, `"keydown"`).
     * @param {string} params.selector
     *        CSS selector used to match targets at dispatch time.
     * @param {Function} params.handler
     *        Handler invoked when a match occurs. Called with `this` bound to the
     *        matched element and the event passed as the only argument.
     * @param {Object|boolean} [params.options]
     *        `addEventListener` options object or capture boolean. This value is
     *        used to bucket native listeners; capture/passive/once must match for
     *        removal.
     * @param {Object} [params.policy]
     *        Optional per-handler dispatch policy.
     * @param {"closest"|"target"} [params.policy.match="closest"]
     *        - `"closest"`: match via host `closest(el, selector)` when provided,
     *          otherwise native `el.closest(selector)`
     *        - `"target"`: match via host `matches(el, selector)` when provided,
     *          otherwise native `el.matches(selector)`
     * @param {boolean} [params.policy.stop=false]
     *        Call `stopImmediatePropagation()` after this handler group fires.
     * @param {boolean} [params.policy.prevent=false]
     *        Call `preventDefault()` when a match occurs.
     * @param {string|number} [params.tag]
     *        Optional tag used for later removal via `off()` (tag mode) or
     *        `offTag(tag)`.
     *
     * @returns {Function}
     *          Unsubscribe function. When called, removes all handlers matching
     *          the same eventType/selector/options and the same handler/tag filter.
     *          If duplicate registrations exist for that signature, all matches are removed.
     *
     * @throws {Error}
     *        If called after `dispose()`.
     * @throws {Error}
     *        If `eventType`, `selector`, or `handler` are invalid.
     *
     * @example
     * const off = delegator.on({
     *   eventType: "click",
     *   selector: ".btn",
     *   handler(e) { console.log("clicked", this); },
     *   tag: "page:settings"
     * });
     *
     * // later
     * off();
     */
    on({ eventType, selector, handler, options = undefined, policy = undefined, tag = undefined } = {}) {
	this._assertNotDisposed();
	this._assertArgs(eventType, selector, handler);

	const rec = this._ensureListener(eventType, options);

	let set = rec.routes.get(selector);
	if (!set) {
            set = new Set();
            rec.routes.set(selector, set);
	}


	const wrapped = {
	    fn: handler,
	    policy: this._normalizePolicy(policy),
	    tag: tag == null ? undefined : String(tag),
	};
	
	set.add(wrapped);

	// Unsubscribe still works (handler-based)
	return () => this.off({ eventType, selector, handler, options, tag });
    }

    /**
     * Set a delegated handler for a selector (replace semantics).
     *
     * This overwrites the entire handler group for the given selector within the
     * `(eventType + options)` bucket. Any previously registered handlers for the
     * same selector (via `on()` or `set()`) are replaced by this single entry.
     *
     * A native listener for the given `(eventType + options)` is created/attached
     * as needed (and only when the service is running).
     *
     * @param {Object} params
     * @param {string} params.eventType
     *        DOM event type (e.g. `"click"`, `"keydown"`).
     * @param {string} params.selector
     *        CSS selector used to match targets at dispatch time.
     * @param {Function} params.handler
     *        Handler invoked when a match occurs. Called with `this` bound to the
     *        matched element and the event passed as the only argument.
     * @param {Object|boolean} [params.options]
     *        `addEventListener` options object or capture boolean. This value is
     *        used to bucket native listeners; capture/passive/once must match for
     *        removal.
     * @param {Object} [params.policy]
     *        Optional per-handler dispatch policy.
     * @param {"closest"|"target"} [params.policy.match="closest"]
     *        - `"closest"`: match via host `closest(el, selector)` when provided,
     *          otherwise native `el.closest(selector)`
     *        - `"target"`: match via host `matches(el, selector)` when provided,
     *          otherwise native `el.matches(selector)`
     * @param {boolean} [params.policy.stop=false]
     *        Call `stopImmediatePropagation()` after this handler group fires.
     * @param {boolean} [params.policy.prevent=false]
     *        Call `preventDefault()` when a match occurs.
     * @param {string|number} [params.tag]
     *        Optional tag stored on the handler entry for later removal via
     *        `off()` (tag mode) or `offTag(tag)`.
     *
     * @returns {Function}
     *          Unsubscribe function. When called, removes handlers matching the
     *          same eventType/selector/options and the same handler/tag filter.
     *
     * @throws {Error}
     *        If called after `dispose()`.
     * @throws {Error}
     *        If `eventType`, `selector`, or `handler` are invalid.
     *
     * @example
     * // Replace any existing ".btn" click handlers with a single handler.
     * const off = delegator.set({
     *   eventType: "click",
     *   selector: ".btn",
     *   handler(e) { console.log("only handler now"); },
     *   tag: "page:settings"
     * });
     *
     * // later
     * off();
     */
    set({ eventType,selector,handler,options = undefined,policy = undefined,tag = undefined } = {}) {
	this._assertNotDisposed();
	this._assertArgs(eventType, selector, handler);

	const rec = this._ensureListener(eventType, options);

	const set = new Set();
	set.add({
            fn: handler,
            policy: this._normalizePolicy(policy),
            tag: tag == null ? undefined : String(tag),
	});

	// "set" semantics: replace everything for this selector
	rec.routes.set(selector, set);

	// Unsubscribe: remove exactly what we set (include tag for precision)
	return () => {
            this.off({ eventType, selector, handler, options, tag });
	};
    }

    /**
     * Remove delegated handlers for a selector.
     *
     * Removal is scoped to a single `(eventType + options)` bucket. Within that bucket,
     * removal targets the given `selector`, and may optionally be filtered by `handler`
     * and/or `tag`.
     *
     * Supported modes:
     * - No `handler` and no `tag`  → remove *all* handlers for the selector.
     * - `handler` only            → remove entries whose `fn === handler`.
     * - `tag` only                → remove entries whose `tag === String(tag)`.
     * - `handler` + `tag`         → remove entries matching both.
     *
     * If removing handlers empties the selector route, the selector is removed.
     * If removing selectors empties the `(eventType + options)` bucket, the native
     * listener is detached from the root and the bucket is deleted.
     *
     * @param {Object} params
     * @param {string} params.eventType
     *        DOM event type (e.g. `"click"`).
     * @param {string} params.selector
     *        CSS selector route to remove from.
     * @param {Function} [params.handler]
     *        Optional handler function reference used to remove a specific handler.
     * @param {Object|boolean} [params.options]
     *        `addEventListener` options object or capture boolean. Must match the
     *        registration options (capture/passive/once) to affect the same bucket.
     * @param {string|number} [params.tag]
     *        Optional tag used to remove tagged entries.
     *
     * @returns {void}
     *
     * @throws {Error}
     *        If called after `dispose()`.
     *
     * @example
     * // Remove all handlers for the selector
     * delegator.off({ eventType: "click", selector: ".btn" });
     *
     * @example
     * // Remove one specific handler for the selector
     * delegator.off({ eventType: "click", selector: ".btn", handler });
     *
     * @example
     * // Remove all tagged handlers for the selector (SPA teardown)
     * delegator.off({ eventType: "click", selector: ".btn", tag: "page:settings" });
     *
     * @example
     * // Remove only the tagged instance of a handler
     * delegator.off({ eventType: "click", selector: ".btn", handler, tag: "page:settings" });
     */
    off({ eventType, selector, handler = undefined, options = undefined, tag = undefined } = {}) {
	this._assertNotDisposed();
	if (!eventType || !this._events.has(eventType)) return;

	const optionsKey = this._optionsKey(options);
	const bucket = this._events.get(eventType);
	const rec = bucket && bucket.get(optionsKey);
	if (!rec) return;

	const set = rec.routes.get(selector);
	if (!set) return;

	const hasHandler = typeof handler === "function";
	const hasTag = tag != null;

	// no handler + no tag => nuke selector route
	if (!hasHandler && !hasTag) {
            rec.routes.delete(selector);
	} else {
            const t = hasTag ? String(tag) : null;

            for (const wrapped of Array.from(set)) {
		const matchHandler = !hasHandler || wrapped.fn === handler;
		const matchTag = !hasTag || wrapped.tag === t;

		if (matchHandler && matchTag) set.delete(wrapped);
            }

            if (set.size === 0) rec.routes.delete(selector);
	}

	// cleanup native listener if empty
	if (rec.routes.size === 0) {
            this._removeListener(eventType, rec.listenerFn, rec.options);
            bucket.delete(optionsKey);
            if (bucket.size === 0) this._events.delete(eventType);
	}
    }
    

    /**
     * Remove all delegated handlers associated with a tag.
     *
     * This is a convenience method intended for SPA/module teardown. It removes
     * any handler entries whose `tag === String(tag)` across:
     * - all event types
     * - all selectors
     * - all options buckets
     *
     * As routes/buckets become empty, the delegator will detach the corresponding
     * native listeners from the root and clean up internal state.
     *
     * @param {string|number|null|undefined} tag
     *        Tag to remove. If `null`/`undefined`, this method is a no-op.
     *
     * @returns {void}
     *
     * @throws {Error}
     *        If called after `dispose()`.
     *
     * @example
     * // Register handlers with a page/module tag
     * delegator.on({ eventType: "click", selector: ".btn", handler, tag: "page:settings" });
     * delegator.on({ eventType: "keydown", selector: "input", handler: onKey, tag: "page:settings" });
     *
     * // Later, tear down everything from that page/module in one call
     * delegator.offTag("page:settings");
     */
    offTag(tag) {
	this._assertNotDisposed();
	if (tag == null) return;

	const t = String(tag);

	for (const [eventType, bucket] of Array.from(this._events.entries())) {
            for (const [optionsKey, rec] of Array.from(bucket.entries())) {
		// Walk selectors
		for (const [selector, set] of Array.from(rec.routes.entries())) {
                    // Remove wrapped entries matching the tag
                    for (const wrapped of Array.from(set)) {
			if (wrapped.tag === t) set.delete(wrapped);
                    }

                    if (set.size === 0) rec.routes.delete(selector);
		}

		// If no selectors remain, remove native listener
		if (rec.routes.size === 0) {
                    this._removeListener(eventType, rec.listenerFn, rec.options);
                    bucket.delete(optionsKey);
		}
            }

            if (bucket.size === 0) this._events.delete(eventType);
	}
    }

    // -----------------------------
    // Public API – inspection
    // -----------------------------

    /**
     * List currently registered delegation routes.
     *
     * Returns a snapshot of the internal routing table suitable for inspection,
     * monitoring, or building a custom console/UI.
     *
     * Each entry describes a single `(eventType, selector, options)` route and
     * includes handler counts and tag aggregation (but does not expose handler
     * function references).
     *
     * @param {string} [eventType]
     *        Optional event type filter. If provided, only routes for that event
     *        type are returned.
     *
     * @returns {Array<{
     *   eventType: string,
     *   selector: string,
     *   count: number,
     *   tags: string[],
     *   tagCounts: Record<string, number>,
     *   options: Object
     * }>}
     *        Array of route descriptors.
     *
     * @example
     * // List everything
     * console.table(delegator.list());
     *
     * @example
     * // List only click routes
     * console.table(delegator.list("click"));
     */
    list(eventType = undefined) {
	const out = [];

	const pushBucket = (type, bucket) => {
            for (const rec of bucket.values()) {
		for (const [selector, set] of rec.routes.entries()) {
                    const tagCounts = Object.create(null);

                    for (const wrapped of set) {
			const t = wrapped.tag;
			if (t == null) continue;
			tagCounts[t] = (tagCounts[t] || 0) + 1;
                    }

                    const tags = Object.keys(tagCounts);

                    out.push({
			eventType: type,
			selector,
			count: set.size,
			tags,        // unique tags present
			tagCounts,   // counts per tag
			options: rec.options
                    });
		}
            }
	};

	if (eventType) {
            const bucket = this._events.get(eventType);
            if (!bucket) return out;
            pushBucket(eventType, bucket);
            return out;
	}

	for (const [type, bucket] of this._events.entries()) {
            pushBucket(type, bucket);
	}

	return out;
    }

    /**
     * Count registered delegated handlers.
     *
     * Returns the total number of handler entries currently registered.
     * The count may be optionally scoped to a specific event type.
     *
     * This is a convenience method built on top of {@link list}.
     *
     * @param {string} [eventType]
     *        Optional event type filter. If provided, only handlers registered
     *        for that event type are counted.
     *
     * @returns {number}
     *          Total number of registered handlers.
     *
     * @example
     * delegator.count();        // total handlers
     * delegator.count("click"); // handlers registered for "click"
     */
    count(eventType = undefined) {
	let n = 0;
	for (const item of this.list(eventType)) n += item.count;
	return n;
    }
    

    // -----------------------------
    // Public API – teardown
    // -----------------------------
    
    /**
     * Clear delegated handlers.
     *
     * Removes registered routes and detaches the corresponding native listeners.
     * This is a destructive operation that clears internal state.
     * Attempts to detach the corresponding native listeners (best-effort; no error if root is unset).
     *
     * When an `eventType` is provided, only handlers for that event type are cleared.
     * Otherwise, all handlers for all event types are removed.
     *
     * Service semantics:
     * - Native listeners for cleared routes are detached.
     * - The running/paused state flag is not modified (clearing routes does not stop the service).
     *
     * @param {string} [eventType]
     *        Optional event type to clear. If omitted, all event types are cleared.
     *
     * @returns {void}
     *
     * @throws {Error}
     *        If called after `dispose()`.
     *
     * @example
     * // Clear all handlers
     * delegator.clear();
     *
     * @example
     * // Clear only click handlers
     * delegator.clear("click");
     */
    clear(eventType = undefined) {
	this._assertNotDisposed();
	this._teardownListeners(eventType,true);

	if (eventType) {
            // remove routes for that event type
            this._events.delete(eventType);
            return;
	}

	this._events.clear();
    }
    /**
     * Dispose the delegator.
     *
     * Permanently tears down the delegator by:
     * - Detaching all native listeners
     * - Clearing all registered routes and handlers
     * - Marking the instance as disposed
     *
     * After disposal:
     * - All public methods that mutate state will throw
     * - The instance must not be reused
     *
     * This is a terminal operation.
     *
     * @returns {void}
     *
     * @example
     * delegator.dispose();
     *
     * // Any further use is invalid
     * // delegator.on(...) → throws
     */
    dispose() {
	if (this._disposed) return;
	this.clear();
	this._disposed = true;
	this._running  = false;
    }


    // -----------------------------
    // Internal – guards
    // -----------------------------
    _assertNotDisposed() {
	if (this._disposed) throw new Error("[delegator] is disposed");
    }
    _assertRoot() {
	if (this.root == null) {
            throw new Error("[delegator] root is not set; call setRoot(root)");
	}
	if (typeof this._rootAdd !== "function") {
            throw new Error("[delegator] root.addEventListener is unavailable");
	}
	if (typeof this._rootRemove !== "function") {
            throw new Error("[delegator] root.removeEventListener is unavailable");
	}
    }
    _assertArgs(eventType, selector, handler) {
	if (typeof eventType !== "string" || !eventType.trim()) {
            throw new Error("[delegator] eventType must be a non-empty string");
	}
	if (typeof selector !== "string" || !selector.trim()) {
            throw new Error("[delegator] selector must be a non-empty string");
	}
	if (typeof handler !== "function") {
            throw new Error("[delegator] handler must be a function");
	}

	// Optional selector validation (policy lives in host)
	if (this.host && typeof this.host.validateSelector === "function") {
            try {
		this.host.validateSelector(selector);
            } catch (err) {
		throw new Error(`[delegator] invalid selector "${selector}"`);
            }
	}
    }

    // -----------------------------
    // Internal – normalization
    // -----------------------------
    _normalizeOptions(options) {
	// allow boolean capture as shorthand
	if (typeof options === "boolean") return { capture: options };

	// allow undefined
	if (!options) return {};

	// shallow clone to avoid mutation surprises
	if (typeof options === "object") return { ...options };

	// fallback
	return {};
    }

    _optionsKey(options) {
	const o = this._normalizeOptions(options);

	// capture is the only thing add/removeEventListener truly needs to match,
	// but we include others to keep separate listeners for separate option sets.
	const capture = !!o.capture;
	const passive = !!o.passive;
	const once = !!o.once;

	return `c:${capture}|p:${passive}|o:${once}`;
    }

    _normalizePolicy(policy) {
	const p = policy && typeof policy === "object" ? policy : {};
	return {
	    match: p.match === "target" ? "target" : "closest",
	    stop: !!p.stop,
	    prevent: !!p.prevent
	};
    }
    
    // -----------------------------
    // Internal – listener management
    // -----------------------------
    
    _ensureListener(eventType, options) {
	const normalizedOptions = this._normalizeOptions(options);
	const optionsKey = this._optionsKey(normalizedOptions);

	let bucket = this._events.get(eventType);
	if (!bucket) {
	    bucket = new Map();
	    this._events.set(eventType, bucket);
	}

	let rec = bucket.get(optionsKey);
	if (rec) return rec;

	rec = {
	    options: normalizedOptions,
	    routes: new Map(), // selector -> Set<{fn, policy, tag}>
	    listenerFn: null
	};

	rec.listenerFn = (e) => {
	    // Shadow DOM-aware target resolution
	    const hostGetPath = this.host && typeof this.host.getPath === "function"
		? this.host.getPath
		: null;
	    let path = null;
	    if (hostGetPath) {
		try {
		    path = hostGetPath.call(this.host, e);
		} catch (_) {
		    path = null;
		}
	    } else {
		path = (e && typeof e.composedPath === "function") ? e.composedPath() : null;
	    }

	    // Normalize event target (Text node -> parentElement)
	    let t = e && e.target;
	    if (t && t.nodeType === 3) t = t.parentElement;

	    // Best candidate element:
	    // - if composedPath exists, take first Element in path
	    // - else use normalized target
	    let baseEl = null;
	    if (path && path.length) {
		for (const it of path) {
		    if (it && it.nodeType === 1) { // Element
			baseEl = it;
			break;
		    }
		}
	    }
	    if (!baseEl) baseEl = t && t.nodeType === 1 ? t : null;
	    if (!baseEl) return;

	    // Dispatch: iterate selectors registered for this eventType/optionsKey
	    // NOTE: Map iteration order is insertion order (predictable).
	    for (const [selector, set] of rec.routes.entries()) {
		let matched = null;

		// match strategy
		// - target: only if baseEl matches selector
		// - closest: nearest ancestor match
		// We also guard matches/closest availability.
		if (set.size === 0) continue;

		// All wrapped entries share selector but may have different policies.
		// We'll compute match once, then apply to all.
		if (this._hasMatch(baseEl, selector)) {
		    // cheapest first
		    if (this._anyPolicyWantsTarget(set)) {
			matched = baseEl;
		    }
		}

		if (!matched) {
		    // default to closest if any handler uses closest (or mixed)
		    const wantClosest = this._anyPolicyWantsClosest(set);
		    if (wantClosest) {
			matched = this._closestMatch(baseEl, selector);
		    }
		}

		if (!matched) continue;

		// Execute handlers
		for (const wrapped of Array.from(set)) {
		    const pol = wrapped.policy;

		    if (pol.prevent && e && typeof e.preventDefault === "function") {
			e.preventDefault();
		    }

		    // If handler throws, we don't take down the dispatcher by default.
		    // (industry convention: isolate handler faults)
		    try {
			wrapped.fn.call(matched, e);
		    } catch (err) {
			this._callbackError(err, e, eventType, selector, matched);
		    }

		    if (pol.stop && e && typeof e.stopImmediatePropagation === "function") {
			e.stopImmediatePropagation();
			return;
		    }
		}
	    }
	};
	if (this._running) {
	    this._addListener(eventType, rec.listenerFn, rec.options);
	}
	bucket.set(optionsKey, rec);
	return rec;
    }

    _addListener(eventType, listenerFn, options) {
	this._assertRoot();
	this._rootAdd.call(this.root, eventType, listenerFn, options);
    }
    _removeListener(eventType, listenerFn, options) {
	this._assertRoot();
	this._rootRemove.call(this.root, eventType, listenerFn, options);
    }
    

    // -----------------------------
    // Internal – error handling
    // -----------------------------

    // Internal error funnel.
    // All handler errors flow through here.
    _callbackError(err, event, eventType, selector, matched) {
	const context = {
	    eventType,
	    selector,
	    event,
	    matched
	};

	if (this.host && typeof this.host.onError === "function") {
	    try {
		this.host.onError(err, context);
	    } catch (_) {
		// never let host.onError take down the delegator.
	    }
	}

	if (!this.callbackError) return;

	const msg = `[delegator] handler error for ${eventType} ${selector}: ${err?.message || err}`;

	try {
            this.callbackError(msg, err, context);
	} catch (_) {
            // never let error handlers take down the delegator.
	}
    }

    
    // -----------------------------
    // Internal – policy helpers
    // -----------------------------
    
    _anyPolicyWantsClosest(set) {
	for (const w of set) if (!w.policy || w.policy.match !== "target") return true;
	return false;
    }

    _anyPolicyWantsTarget(set) {
	for (const w of set) if (w.policy && w.policy.match === "target") return true;
	return false;
    }
    _hasMatch(el, selector) {
	if (!el) return false;

	const hostMatches = this.host && typeof this.host.matches === "function"
	    ? this.host.matches
	    : null;

	if (hostMatches) {
	    try {
		return !!hostMatches.call(this.host, el, selector);
	    } catch (_) {
		// fallback to native element matching
	    }
	}

	return typeof el.matches === "function" ? !!el.matches(selector) : false;
    }

    _closestMatch(el, selector) {
	if (!el) return null;

	const hostClosest = this.host && typeof this.host.closest === "function"
	    ? this.host.closest
	    : null;

	if (hostClosest) {
	    try {
		return hostClosest.call(this.host, el, selector) || null;
	    } catch (_) {
		// fallback to native element closest()
	    }
	}

	return typeof el.closest === "function" ? el.closest(selector) : null;
    }

    // -----------------------------
    // Internal – teardown / setup of listeners
    // -----------------------------

    _setupListeners(eventType = undefined) {
	if (eventType) {
            const bucket = this._events.get(eventType);
            if (!bucket) return;
            for (const rec of bucket.values()) {
		this._addListener(eventType, rec.listenerFn, rec.options);
            }
            return;
	}

	for (const [type, bucket] of this._events.entries()) {
            for (const rec of bucket.values()) {
		this._addListener(type, rec.listenerFn, rec.options);
            }
	}
    }

    _teardownListeners(eventType = undefined, soft = false) {
	const errors = [];

	const teardownBucket = (type, bucket) => {
            for (const rec of bucket.values()) {
		try {
                    this._removeListener(type, rec.listenerFn, rec.options);
		} catch (e) {
                    if (!soft) throw e;
                    errors.push(e);
		}
            }
	};

	if (eventType) {
            const bucket = this._events.get(eventType);
            if (!bucket) return;
            teardownBucket(eventType, bucket);
	} else {
            for (const [type, bucket] of this._events.entries()) {
		teardownBucket(type, bucket);
            }
	}

	//discard errors for now if soft.
    }
}


/**
 * @typedef {Object} EventDelegatorConfig
 * @property {EventTarget} [root]
 *        Root event target to attach native listeners to.
 * @property {Object|Function|null} [host]
 *        Optional host/environment surface.
 * @property {Function|null} [callbackError]
 *        Optional error handling policy.
 */

/**
 * @typedef {Object} DelegatorPolicy
 * @property {"closest"|"target"} [match="closest"]
 *        Matching strategy for selectors.
 * @property {boolean} [stop=false]
 *        Call stopImmediatePropagation after handler group fires.
 * @property {boolean} [prevent=false]
 *        Call preventDefault when a match occurs.
 */

/**
 * @typedef {Object} DelegatorOnParams
 * @property {string} eventType
 * @property {string} selector
 * @property {Function} handler
 * @property {Object|boolean} [options]
 * @property {DelegatorPolicy} [policy]
 * @property {string|number} [tag]
 */

/**
 * @typedef {Object} DelegatorOffParams
 * @property {string} eventType
 * @property {string} selector
 * @property {Function} [handler]
 * @property {Object|boolean} [options]
 * @property {string|number} [tag]
 */

/**
 * @typedef {Object} ListenerRecord
 * @property {Object} options
 *        Native addEventListener options for this bucket.
 * @property {Map<string, Set<WrappedHandler>>} routes
 *        Selector-to-handler routing table.
 * @property {Function} listenerFn
 *        Native listener function attached to the root.
 */

/**
 * @typedef {Object} WrappedHandler
 * @property {Function} fn
 *        User-provided handler function.
 * @property {DelegatorPolicy} policy
 *        Normalized dispatch policy.
 * @property {string|undefined} tag
 *        Optional tag used for teardown and introspection.
 */

/**
 * @typedef {Object} DelegatorListEntry
 * @property {string} eventType
 * @property {string} selector
 * @property {number} count
 *        Number of handlers registered for this route.
 * @property {string[]} tags
 *        Unique tags present for this route.
 * @property {Object<string, number>} tagCounts
 *        Count of handlers per tag.
 * @property {Object} options
 *        Native listener options associated with this route.
 */
export default EventDelegator;
